import SwiftUI
import SwiftData
struct CodeGeneratorSheet: View { @Environment(\.modelContext) private var modelContext; @Environment(\.dismiss) private var dismiss; @State private var generatedCodes: [RedeemCode] = []; @State private var note: String = ""; @State private var count: Int = 1; @State private var copiedCode: String?; let counts = [1, 3, 5, 10]
    var body: some View { NavigationStack { List { Section { HStack { Text("生成数量").font(.cnBody).foregroundColor(.textPrimary); Spacer(); Picker("", selection: $count) { ForEach(counts, id: \.self) { n in Text("\(n) 个").tag(n) } }.pickerStyle(.segmented).frame(width: 200) }; HStack { Image(systemName: "pencil.line").font(.system(size: 18)).foregroundColor(.textTertiary).frame(width: 24); TextField("备注（给谁的？）", text: $note).font(.cnBody).foregroundColor(.textPrimary) }; Button { generate() } label: { HStack { Image(systemName: "sparkles").font(.system(size: 14)); Text("生成邀请码").font(.cnHeadline) }.frame(maxWidth: .infinity).padding(.vertical, Spacing.sm) }.tint(.tealLink).buttonStyle(.borderedProminent).listRowBackground(Color.clear) } header: { Text("生成新码") }; if !generatedCodes.isEmpty { Section { ForEach(generatedCodes.reversed()) { code in codeRow(code) }.onDelete { offsets in let reversed = generatedCodes.reversed(); let ids = offsets.map { reversed[$0] }; for code in ids { modelContext.delete(code) }; try? modelContext.save(); generatedCodes.removeAll { ids.contains($0) } } } header: { Text("已生成的邀请码（\(generatedCodes.filter { !$0.isUsed }.count) 个可用）") } footer: { Text("每个码仅可使用一次。长按复制，左滑删除。") } }; let usedCodes = generatedCodes.filter { $0.isUsed }; if !usedCodes.isEmpty { Section { ForEach(usedCodes.reversed()) { code in codeRow(code) } } header: { Text("已使用") } } }.listStyle(.insetGrouped).scrollContentBackground(.hidden).background(Color.surfaceLight).navigationTitle("邀请码管理").toolbar { ToolbarItem(placement: .topBarTrailing) { Button("完成") { dismiss() } } } } }
    private func generate() { let newCodes = RedeemCodeManager.shared.generateCodes(count: count, note: note.isEmpty ? nil : note, modelContext: modelContext); generatedCodes.append(contentsOf: newCodes); note = "" }
    private func codeRow(_ redeemCode: RedeemCode) -> some View { HStack(spacing: Spacing.md) { VStack(alignment: .leading, spacing: 4) { Text(redeemCode.code).font(.cnTitle3.monospaced()).foregroundColor(redeemCode.isUsed ? .textTertiary : .textPrimary); if let note = redeemCode.note { Text(note).font(.cnCaption1).foregroundColor(.textTertiary) } }; Spacer(); if redeemCode.isUsed { HStack(spacing: 4) { Image(systemName: "checkmark.circle.fill").font(.system(size: 12)); Text("已使用").font(.cnCaption2) }.foregroundColor(.textTertiary) } else { Button { Clipboard.copy(redeemCode.code); copiedCode = redeemCode.code; Task { try? await Task.sleep(nanoseconds: 2_000_000_000); if copiedCode == redeemCode.code { copiedCode = nil } } } label: { HStack(spacing: 4) { Image(systemName: copiedCode == redeemCode.code ? "checkmark" : "doc.on.doc").font(.system(size: 12)); Text(copiedCode == redeemCode.code ? "已复制" : "复制").font(.cnCaption2) }.foregroundColor(.tealLink) } } }.padding(.vertical, Spacing.xs) }
}